Refactor this function to use early-return instead of nested ifs:

function grade(score: number): string {
  let result;
  if (score >= 0) {
    if (score < 60) {
      result = 'F';
    } else {
      if (score < 70) {
        result = 'D';
      } else {
        if (score < 80) {
          result = 'C';
        } else {
          if (score < 90) {
            result = 'B';
          } else {
            result = 'A';
          }
        }
      }
    }
  } else {
    result = 'invalid';
  }
  return result;
}
